<script>

export default {
    components: {

    },
    props: {


    },
    data() {
        return {
            activeTab: 'details',
            selectedDeviceId: 1,
            syncLogs: [
                { time: "2023-10-15 14:05:00", message: "Data synchronization completed", status: "success" },
                { time: "2023-10-15 13:50:00", message: "Visitor logs uploaded", status: "success" },
                { time: "2023-10-15 13:35:00", message: "Cache cleared and rebuilt", status: "success" }
            ],
            deviceForm: {
                deviceName: '',
                deviceId: '',
                deviceModel: '',
                location: '',
                faceAuthUrl: '',
                syncFrequency: "Daily",
                deviceStatus: 'active'
            },
            scheduleTimes: [
                { time: '' }
            ],
            errors: {}

        };
    },
    mounted() {
        // Example existing device data
        const existingDevice = {
            deviceName: 'Main Entrance Kiosk',
            deviceId: 'KIOSK-001',
            deviceModel: 'Samsung Tab A7',
            location: 'Main Lobby',
            faceAuthUrl: 'http://localhost:5000/face-auth',
            syncFrequency: "Daily",
            deviceStatus: 'active',


        };
        this.scheduleTimes = [{ time: '20:39' }, { time: "19:40" }];

        this.deviceForm = { ...existingDevice };
    },
    methods: {
        addSchedule() {
            this.scheduleTimes.push({ time: '' });
        },

        removeSchedule(index) {
            this.scheduleTimes.splice(index, 1);
        },
        handleClose() {
            this.$emit("close");
        },
        validateScheduleTimes() {
            for (const item of this.scheduleTimes) {
                if (!item.time) {
                    return 'Date and time are required';
                }
            }

            return null;
        },
        validateForm() {
            this.errors = {};

            if (!this.deviceForm.deviceName) {
                this.errors.deviceName = 'Device name is required';
            }

            if (!this.deviceForm.deviceId) {
                this.errors.deviceId = 'Device ID is required';
            }

            if (!this.deviceForm.location) {
                this.errors.location = 'Location is required';
            }

            if (!this.deviceForm.faceAuthUrl) {
                this.errors.faceAuthUrl = 'Face Auth URL is required';
            } else if (!/^https?:\/\//i.test(this.deviceForm.faceAuthUrl)) {
                this.errors.faceAuthUrl = 'Invalid URL format';
            }

            return Object.keys(this.errors).length === 0;
        },
        clearError(field) {
            if (this.errors[field]) {
                this.$delete(this.errors, field);
            }
        },
        submitForm() {
            if (!this.validateForm()) {
                this.activeTab = 'details';
                return;
            }


            const payload = {
                ...this.deviceForm,
                deviceId: this.selectedDeviceId,
                schedules: this.scheduleTimes.map(s => ({
                    time: `${s.time}`
                }))
            };

            console.log('Submitting device data:', payload);

            // 🔥 API call example
            // this.$emit('save', payload)

            alert('Device updated successfully');
        }
    }
}
</script>
